import functools

class RateLimiter:
    def __init__(self, allowed_ips):
        self.allowed_ips = set(allowed_ips)

    def rate_limit(self, reqs):
        start_time = datetime.now()
        total_requests = len(reqs)

        # Adjust request counter based on allowed IPs
        ip_counter = {ip: total_requests // 50 for ip in self.allowed_ips}

        if time.time() - start_time > (total_requests + 1) * 60:
            end_time = datetime.now()

            for ip, count in ip_counter.items():
                self.logger.info(f"IP {ip}: Request limit reached ({end_time}). Requiring {count} requests.")

            return max(ip_counter.values(), key=ip_counter.get)

        return min(ip_counter.values())

# Example usage
rate_limiter = RateLimiter(['192.168.1.1', '10.0.0.1'])
print(rate_limiter.rate_limit([1, 2, 3]))  # Returns 3
print(rate_limiter.rate_limit([4, 5]))     # Returns 4
```

