Here's an example of a simple memory allocator in C++:

```cpp
#include <cassert>

// Allocator class
class MemoryAllocator {
public:
    // Constructor to allocate memory
    MemoryAllocator() : size_(0), data_(nullptr) {}

    // Destructor to deallocate allocated memory
    ~MemoryAllocator() {
        if (data_) delete[] data_;
    }

    // Allocate memory on-the-fly with a given size
    void* Allocate(size_t size) {
        assert(size > 0);

        // Check if memory is already free
        if (!data_) {
            auto ptr = std::malloc(size);
            assert(ptr);
            data_ = ptr;
            return ptr;
        } else {
            // Free previously allocated space
            std::free(data_);
            data_ = nullptr;
            return nullptr;
        }
    }

    // Deallocate memory from the allocator
    void Release(void* p) {
        if (p != data_) {
            std::free(p);
            data_ = nullptr;
        }
    }

private:
    int size_; // Size in bytes
    void* data_; // Pointer to stored data
};
```

